import Accordion from '@/components/Accordion';
import {
  Table,
  TableBody,
  TableCaption,
  TableCell,
  TableHead,
  TableHeader,
  TableRow
} from '@/components/ui/table';
import Technology from '@/types/Technology';
import { Terminal } from 'lucide-react';
import Image from 'next/image';
import AccordionButtons from './components/AccordionItems/AccordionButtons';
import Form from '@/components/Form';
import Label from '../login/components/Label';
import Input from '../login/components/Input';
import { createTechnologyAction } from './actions';

export default async function AdminPage() {
  
  return (
    <>
      <section className="relative flex h-screen flex-col items-center px-0 py-6 text-white lg:p-16">
        <h1 className="mb-5 flex items-center gap-4 tracking-wider">
          <span className="animate-pulse">
            <Terminal style={{ color: 'var(--color-primary)' }} size={40} />
          </span>
          OLÁ JOEL!
        </h1>
        <section className="w-full px-2 md:px-8">
          <Table className="w-full text-gray lg:w-7/10 lg:justify-self-center lg:text-lg dark:text-white">
            <TableCaption className='lg:text-lg'>Lista de Tecnologias</TableCaption>
            <TableHeader className="lg:text-xl">
              <TableRow>
                <TableHead className="text-start">Logo</TableHead>
                <TableHead className="text-center">Nome</TableHead>
                <TableHead className="text-center md:text-right">
                  Opções
                </TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {technologies.map((technology) => (
                <TableRow key={technology.id}>
                  <TableCell className="w-[100px] text-center">
                    <Image
                      src={
                        technology.logo?.imageLink ?? 'https://picsum.photos/25'
                      }
                      alt={technology.logo?.name ?? ' logo'}
                      width={25}
                      height={25}
                    />
                  </TableCell>
                  <TableCell className="w-[50px] p-0 text-center text-sm lg:text-lg">
                    {technology.name}
                  </TableCell>
                  <TableCell className="text-center">
                    <AccordionButtons identifier={technology.id} />
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
          <Accordion>
            <Form action={createTechnologyAction}>
              <Label htmlFor="technologyName">Nome da Tecnologia</Label>
              <Input name="technologyName" id="technologyName" type="text" />
              <Label htmlFor="technologyImageName">Nome da imagem</Label>
              <Input
                name="technologyImageName"
                id="technologyImageName"
                type="text"
              />
              <Label htmlFor="technologyImageLink">Link da imagem</Label>
              <Input
                name="technologyImageLink"
                id="technologyImageLink"
                type="text"
              />
            </Form>
          </Accordion>
        </section>
      </section>
    </>
  );
}
